import{_ as a,o as i,c as e,aa as t}from"./chunks/framework.DHLMKRb3.js";const u=JSON.parse('{"title":"Total War Lua Console Guide (Rome 2 & Attila)","description":"Total War Lua console. Learn how to execute raw Lua scripts, trigger events, and interact with the game model in real-time within Rome II and Attila.","frontmatter":{"outline":"deep","title":"Total War Lua Console Guide (Rome 2 & Attila)","description":"Total War Lua console. Learn how to execute raw Lua scripts, trigger events, and interact with the game model in real-time within Rome II and Attila."},"headers":[],"relativePath":"guide/console-manual.md","filePath":"guide/console-manual.md","lastUpdated":1775689403000}'),n={name:"guide/console-manual.md"};function o(l,s,r,h,p,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="commands-lua-console" tabindex="-1">Commands &amp; Lua Console <a class="header-anchor" href="#commands-lua-console" aria-label="Permalink to &quot;Commands &amp; Lua Console&quot;">​</a></h1><p>The console is a simple TextInput UI element.</p><h2 id="how-input-is-processed" tabindex="-1">How Input is Processed <a class="header-anchor" href="#how-input-is-processed" aria-label="Permalink to &quot;How Input is Processed&quot;">​</a></h2><p>Type in the input field and click <strong>Send</strong>.<br> The console differentiates between two types of input:</p><h3 id="_1-slash-commands" tabindex="-1">1. Slash Commands <a class="header-anchor" href="#_1-slash-commands" aria-label="Permalink to &quot;1. Slash Commands&quot;">​</a></h3><p>Any input starting with a / is matched against the <a href="./../reference/console-commands">Command Registry</a>.<br> For example, <code>/help</code> will list all built-in commands.</p><div class="warning custom-block"><p class="custom-block-title">Input field truncates long text</p><p>Pasting more than a few lines will silently cut the input and produce an <code>unfinished string near &#39;&lt;eof&gt;&#39;</code> error. Use <strong>Scriptum</strong> for anything longer than a short expression.</p></div><div class="warning custom-block"><p class="custom-block-title">No Enter key</p><p>You cannot press Enter to send - you must click the <strong>Send</strong> button each time.</p></div><div class="warning custom-block"><p class="custom-block-title">No output copy</p><p>You cannot select or copy text from the console output. All output is also written to consul.output in the game root folder - open it in a text editor.</p></div><h3 id="_2-lua-mode" tabindex="-1">2. Lua Mode <a class="header-anchor" href="#_2-lua-mode" aria-label="Permalink to &quot;2. Lua Mode&quot;">​</a></h3><p>Anything that does <strong>not</strong> start with <code>/</code> is treated as raw Lua and executed directly in the game&#39;s scripting environment. The full game scripting API is available - you can use the console to register listeners, trigger events, or interact with the internal game model on the fly.</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Write to the console output</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">consul.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">console</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;hello from Lua&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Access the game model</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">local</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> world </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> consul.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">_game</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">():</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">():</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">world</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">consul.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">console</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Factions: &quot; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> world</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">faction_list</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">():</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">num_items</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Modder &amp; Script Authors</p><p>The functions shown above are part of the core ConsulScriptum API. You can use these identical calls in your own external .lua scripts. For a full list of accessible functions, see the <a href="./../reference/internal-lua-api">Internal API Reference</a>.</p></div><div class="tip custom-block"><p class="custom-block-title">Run scripts from Pack Files</p><p>You can use the console to execute <strong>any</strong> script - not just files in your game folder, but also those hidden inside the game&#39;s <code>.pack</code> files.</p><p>This is perfect for reloading internal game scripts or running one-off files:</p><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dofile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lua_scripts/all_scripted.lua&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>If the script fails, the console will print the error message directly to the output.</p></div><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>The console is not &quot;magic&quot;. When you send raw Lua, the system performs a standard Lua execution flow:</p><ol><li>Your input is parsed into a function via <code>loadstring(cmd)</code>.</li><li>That function is then executed within a <code>pcall(f)</code> to catch errors.</li></ol><div class="language-lua vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">lua</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- Behind the scenes:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">local</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f, err </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> loadstring</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(your_input)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> not</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> err </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    pcall</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(f)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><p>This means you are interacting directly with the game&#39;s Lua environment just as you would with any other script.</p><h2 id="command-history" tabindex="-1">Command history <a class="header-anchor" href="#command-history" aria-label="Permalink to &quot;Command history&quot;">​</a></h2><p>Previous commands are saved to consul.history (one per line, max 100 entries). Use the on-screen <strong>up</strong> and <strong>down</strong> buttons to navigate. The keyboard arrow keys do not work.</p><h2 id="auto-clear" tabindex="-1">Auto-clear <a class="header-anchor" href="#auto-clear" aria-label="Permalink to &quot;Auto-clear&quot;">​</a></h2><p>/autoclear toggles automatic clearing of the output area after each command. Useful when running repeated commands and the output gets cluttered.</p><h2 id="available-commands" tabindex="-1">Available Commands <a class="header-anchor" href="#available-commands" aria-label="Permalink to &quot;Available Commands&quot;">​</a></h2><p>To view the list of available commands, see <a href="./../reference/console-commands">Consul Commands</a>.</p><h2 id="custom-commands" tabindex="-1">Custom Commands <a class="header-anchor" href="#custom-commands" aria-label="Permalink to &quot;Custom Commands&quot;">​</a></h2><p>To learn how to add custom commands, see <a href="./../reference/adding-custom-commands">How To Add Custom Commands</a>.</p>`,27)])])}const k=a(n,[["render",o]]);export{u as __pageData,k as default};
